                // CREATE TABLE TEST(A INT, B INT);
                // INSERT INTO TEST VALUES(1, NULL);
                // SELECT * FROM TEST WHERE NOT (B=A AND B=0); // no rows
                // SELECT * FROM TEST WHERE NOT (B=A AND B=0 AND A=0); // 1,
